previewCss:
.darma-loader-darma-custom-088 {
  width: 40px;
  aspect-ratio: 1;
  display: grid;
  animation: darma-loader-darma-custom-088-l8-0 1.5s infinite linear;
}
.darma-loader-darma-custom-088:before,
.darma-loader-darma-custom-088:after {
  content: "";
  grid-area: 1/1;
  background: #25b09b;
  clip-path: polygon(0 0%,100% 0,100% 100%);
  animation: inherit;
  animation-name: darma-loader-darma-custom-088-l8-1;
}
.darma-loader-darma-custom-088:after {
  --s:-1;
}
@keyframes darma-loader-darma-custom-088-l8-0 {
  66%      {transform: skewX(0deg)}
  80%,100% {transform: skewX(-45deg)}
}
@keyframes darma-loader-darma-custom-088-l8-1 {
  0%   {transform:scale(var(--s,1)) translate(-0.5px,0)}
  33%  {transform:scale(var(--s,1)) translate(calc(1px - 50%),calc(1px - 50%))}
  66%  {transform:scale(var(--s,1)) translate(calc(1px - 50%),0%)}
  100% {transform:scale(var(--s,1)) translate(calc(0.5px - 50%),0%)}
}

